(()=>{const mergeObjs=(target,source,options={})=>{const{mergePaths:mergePaths=[],excludePaths:excludePaths=[]}=options;function isObject(obj){return obj&&typeof obj==="object"&&!Array.isArray(obj)}function buildPath(base,cur,append=false){if(base===""){return cur}else if(append){return`${base}.${cur}`}else{return isNaN(cur)?`${base}.${cur}`:`${base}[${cur}]`}}function mergeArrays(targetArr,sourceArr,path){if(targetArr.length===0)return sourceArr;if(isObject(targetArr[0])&&"id"in targetArr[0]){const mergedArray=[...targetArr];sourceArr.forEach((sourceItem=>{const existingItem=mergedArray.find((item=>item.id===sourceItem.id));if(existingItem){deepMerge(existingItem,sourceItem,path)}else{mergedArray.push(sourceItem)}}));return mergedArray}else{return Array.from(new Set([...targetArr,...sourceArr]))}}function deepMerge(target,source,path=""){if(!isObject(target)||!isObject(source)){return target}Object.keys(source).forEach((key=>{const currentPath=buildPath(path,key);if(excludePaths.includes(currentPath)){return}if(mergePaths.includes(currentPath)){if(Array.isArray(source[key])&&Array.isArray(target[key])){target[key]=mergeArrays(target[key],source[key],currentPath)}else if(isObject(source[key])){if(!target[key])target[key]={};deepMerge(target[key],source[key],currentPath)}else{target[key]=source[key]}}else{if(!target.hasOwnProperty(key)){target[key]=source[key]}}}))}deepMerge(target,source);return target};Macro.add("reload",{handler(){const oldData=JSON.parse(JSON.stringify(State.variables));for(const key in State.variables){if(State.variables.hasOwnProperty(key)){delete State.variables[key]}}$.wikiPassage("StoryInit");const newData=JSON.parse(JSON.stringify(State.variables));Object.entries(mergeObjs(oldData,newData,setup.reload_rules||[])).forEach((([key,val])=>{State.variables[key]=val}));setTimeout((()=>Engine.play(passage())),Engine.DOM_DELAY)}});setup.mergeObjs=mergeObjs;window.mergeObjs=window.mergeObjs||mergeObjs})();
/* End Update SaveData */